import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const AdminDashboard = () => {
  const [stats, setStats] = useState({
    totalOrders: 0,
    totalRevenue: 0,
    activeRestaurants: 0,
    deliveryPartners: 0,
    pendingApprovals: 0,
    todayOrders: 0,
    todayRevenue: 0,
    avgOrderValue: 0
  });

  const [recentOrders, setRecentOrders] = useState([]);
  const [recentActivities, setRecentActivities] = useState([]);

  useEffect(() => {
    loadDashboardData();
    // Set up real-time updates every 30 seconds
    const interval = setInterval(loadDashboardData, 30000);
    return () => clearInterval(interval);
    loadRecentOrders();
    loadRecentActivities();
  }, []);

  const loadDashboardStats = () => {
    // Mock data - in real app, this would come from API
    const orders = JSON.parse(localStorage.getItem('orders') || '[]');
    const restaurants = JSON.parse(localStorage.getItem('adminRestaurants') || '[]');
    const deliveryPartners = JSON.parse(localStorage.getItem('adminDeliveryPartners') || '[]');

    const todayOrders = orders.filter(order => {
      const orderDate = new Date(order.createdAt);
      const today = new Date();
      return orderDate.toDateString() === today.toDateString();
    });

    const totalRevenue = orders.reduce((sum, order) => sum + order.totalAmount, 0);
    const activeRestaurants = restaurants.filter(r => r.isActive).length;
    const activeDeliveryPartners = deliveryPartners.filter(dp => dp.isActive).length;
    const pendingApprovals = restaurants.filter(r => r.status === 'pending').length;

    setStats({
      totalOrders: orders.length,
      totalRevenue,
      activeRestaurants,
      activeDeliveryPartners,
      pendingApprovals,
      todayOrders: todayOrders.length
    });
  };

  const loadRecentOrders = () => {
    const orders = JSON.parse(localStorage.getItem('orders') || '[]');
    const recent = orders
      .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
      .slice(0, 5);
    setRecentOrders(recent);
  };

  const loadRecentActivities = () => {
    const activities = JSON.parse(localStorage.getItem('adminActivities') || '[]');
    const recent = activities
      .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp))
      .slice(0, 8);
    setRecentActivities(recent);
  };

  const StatCard = ({ title, value, icon, color, change }) => (
    <div className="bg-white rounded-lg shadow-sm p-6 border-l-4" style={{ borderLeftColor: color }}>
      <div className="flex items-center justify-between">
        <div>
          <p className="text-gray-600 text-sm font-medium">{title}</p>
          <p className="text-2xl font-bold text-gray-900">{value}</p>
          {change && (
            <p className={`text-sm ${change > 0 ? 'text-green-600' : 'text-red-600'}`}>
              {change > 0 ? '+' : ''}{change}% from yesterday
            </p>
          )}
        </div>
        <div className="text-3xl" style={{ color }}>{icon}</div>
      </div>
    </div>
  );

  const QuickActionCard = ({ title, description, icon, link, color }) => (
    <Link
      to={link}
      className="bg-white rounded-lg shadow-sm p-6 hover:shadow-md transition-shadow border-l-4"
      style={{ borderLeftColor: color }}
    >
      <div className="flex items-center space-x-4">
        <div className="text-2xl" style={{ color }}>{icon}</div>
        <div>
          <h3 className="font-semibold text-gray-900">{title}</h3>
          <p className="text-gray-600 text-sm">{description}</p>
        </div>
      </div>
    </Link>
  );

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold text-gray-900">Admin Dashboard</h1>
              <p className="text-gray-600">Welcome back! Here's what's happening with your food delivery platform.</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="text-sm text-gray-600">
                Last updated: {new Date().toLocaleTimeString()}
              </div>
              <button className="bg-orange-500 text-white px-4 py-2 rounded-lg hover:bg-orange-600 transition-colors">
                📊 Generate Report
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
          <StatCard
            title="Total Orders"
            value={stats.totalOrders.toLocaleString()}
            icon="📦"
            color="#f59e0b"
            change={12}
          />
          <StatCard
            title="Total Revenue"
            value={`₹${stats.totalRevenue.toLocaleString()}`}
            icon="💰"
            color="#10b981"
            change={8}
          />
          <StatCard
            title="Active Restaurants"
            value={stats.activeRestaurants}
            icon="🏪"
            color="#3b82f6"
            change={3}
          />
          <StatCard
            title="Delivery Partners"
            value={stats.activeDeliveryPartners}
            icon="🚴"
            color="#8b5cf6"
            change={-2}
          />
          <StatCard
            title="Pending Approvals"
            value={stats.pendingApprovals}
            icon="⏳"
            color="#ef4444"
          />
          <StatCard
            title="Today's Orders"
            value={stats.todayOrders}
            icon="📈"
            color="#06b6d4"
            change={15}
          />
        </div>

        {/* Quick Actions */}
        <div className="mb-8">
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Quick Actions</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <QuickActionCard
              title="User Management"
              description="Manage customers, restaurants, and delivery partners"
              icon="👥"
              link="/admin/users"
              color="#3b82f6"
            />
            <QuickActionCard
              title="Restaurant Approvals"
              description="Review and approve new restaurant registrations"
              icon="✅"
              link="/admin/restaurant-approvals"
              color="#10b981"
            />
            <QuickActionCard
              title="Order Monitoring"
              description="Track all orders and transactions"
              icon="📊"
              link="/admin/orders"
              color="#f59e0b"
            />
            <QuickActionCard
              title="Analytics & Reports"
              description="View detailed analytics and generate reports"
              icon="📈"
              link="/admin/analytics"
              color="#8b5cf6"
            />
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Recent Orders */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-gray-900">Recent Orders</h3>
              <Link to="/admin/orders" className="text-orange-600 hover:text-orange-700 text-sm font-medium">
                View All →
              </Link>
            </div>
            <div className="space-y-4">
              {recentOrders.length > 0 ? recentOrders.map((order) => (
                <div key={order.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div>
                    <p className="font-medium text-gray-900">#{order.id}</p>
                    <p className="text-sm text-gray-600">{order.restaurant?.name}</p>
                    <p className="text-xs text-gray-500">
                      {new Date(order.createdAt).toLocaleString()}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="font-semibold text-gray-900">₹{order.totalAmount}</p>
                    <span className={`inline-flex px-2 py-1 text-xs rounded-full ${
                      order.status === 'delivered' ? 'bg-green-100 text-green-800' :
                      order.status === 'confirmed' ? 'bg-blue-100 text-blue-800' :
                      'bg-yellow-100 text-yellow-800'
                    }`}>
                      {order.status}
                    </span>
                  </div>
                </div>
              )) : (
                <p className="text-gray-500 text-center py-4">No recent orders</p>
              )}
            </div>
          </div>

          {/* Recent Activities */}
          <div className="bg-white rounded-lg shadow-sm p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-gray-900">Recent Activities</h3>
              <Link to="/admin/activities" className="text-orange-600 hover:text-orange-700 text-sm font-medium">
                View All →
              </Link>
            </div>
            <div className="space-y-3">
              {recentActivities.length > 0 ? recentActivities.map((activity, index) => (
                <div key={index} className="flex items-start space-x-3">
                  <div className="flex-shrink-0 w-2 h-2 bg-orange-500 rounded-full mt-2"></div>
                  <div>
                    <p className="text-sm text-gray-900">{activity.description}</p>
                    <p className="text-xs text-gray-500">
                      {new Date(activity.timestamp).toLocaleString()}
                    </p>
                  </div>
                </div>
              )) : (
                <div className="space-y-3">
                  <div className="flex items-start space-x-3">
                    <div className="flex-shrink-0 w-2 h-2 bg-orange-500 rounded-full mt-2"></div>
                    <div>
                      <p className="text-sm text-gray-900">New restaurant "Golden Dragon" registered</p>
                      <p className="text-xs text-gray-500">2 hours ago</p>
                    </div>
                  </div>
                  <div className="flex items-start space-x-3">
                    <div className="flex-shrink-0 w-2 h-2 bg-green-500 rounded-full mt-2"></div>
                    <div>
                      <p className="text-sm text-gray-900">Order #ORD123 delivered successfully</p>
                      <p className="text-xs text-gray-500">3 hours ago</p>
                    </div>
                  </div>
                  <div className="flex items-start space-x-3">
                    <div className="flex-shrink-0 w-2 h-2 bg-blue-500 rounded-full mt-2"></div>
                    <div>
                      <p className="text-sm text-gray-900">New delivery partner "Rajesh Kumar" approved</p>
                      <p className="text-xs text-gray-500">5 hours ago</p>
                    </div>
                  </div>
                  <div className="flex items-start space-x-3">
                    <div className="flex-shrink-0 w-2 h-2 bg-red-500 rounded-full mt-2"></div>
                    <div>
                      <p className="text-sm text-gray-900">Restaurant "Spice Garden" suspended for policy violation</p>
                      <p className="text-xs text-gray-500">1 day ago</p>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* System Health */}
        <div className="mt-8 bg-white rounded-lg shadow-sm p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">System Health</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="text-center">
              <div className="text-2xl text-green-500 mb-2">✅</div>
              <p className="font-medium text-gray-900">All Systems Operational</p>
              <p className="text-sm text-gray-600">Last checked: {new Date().toLocaleTimeString()}</p>
            </div>
            <div className="text-center">
              <div className="text-2xl text-blue-500 mb-2">🔒</div>
              <p className="font-medium text-gray-900">Security Status: Good</p>
              <p className="text-sm text-gray-600">No suspicious activities detected</p>
            </div>
            <div className="text-center">
              <div className="text-2xl text-orange-500 mb-2">📊</div>
              <p className="font-medium text-gray-900">Performance: Optimal</p>
              <p className="text-sm text-gray-600">Average response time: 120ms</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
